#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X;
        scanf("%lld", &X);
        if (X <= 333) {
            printf("BRONZE\n");
        } else if (X <= 666) {
            printf("SILVER\n");
        } else {
            printf("GOLD\n");
        }
    }
    return 0;
}

